sql:
SELECT COUNT(*) AS active_sites_count
FROM sites
WHERE is_active = 1;

SELECT AVG(eco3_bas_pct) AS avg_eco3_bas_pct
FROM sites
WHERE huc8_site = 1010002;

SELECT AVG(eco3_bas_pct) AS average_eco3_bas_pct
FROM sites
WHERE is_active = 1;

SELECT COUNT(site_id) AS number_of_sites
FROM sites
WHERE nutr_bas_pct > 75 AND nutr_bas_dom = 8;

